/**
 * MyBotIA WebSocket Protocol — OpenClaw Gateway v3
 * Gère la connexion WS, le handshake, le ping/pong, et le reconnect.
 *
 * Validé par test E2E : connect.challenge → connect (openclaw-control-ui)
 * → chat.send (sessionKey + message + idempotencyKey) → ok=true
 */

const PROTOCOL_VERSION = 3

/**
 * Dérive un relay token HMAC-SHA256 à partir du gateway token.
 */
export async function deriveRelayToken(gatewayToken, port) {
  const enc = new TextEncoder()
  const key = await crypto.subtle.importKey(
    'raw',
    enc.encode(gatewayToken),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  )
  const sig = await crypto.subtle.sign(
    'HMAC',
    key,
    enc.encode(`openclaw-extension-relay-v1:${port}`)
  )
  return [...new Uint8Array(sig)]
    .map(b => b.toString(16).padStart(2, '0'))
    .join('')
}

/**
 * Calcule le délai de reconnexion avec backoff exponentiel + jitter.
 */
export function reconnectDelayMs(attempt) {
  const baseMs = 1000
  const maxMs = 30000
  const jitterMs = 1000
  const backoff = Math.min(baseMs * 2 ** Math.max(0, attempt), maxMs)
  return backoff + jitterMs * Math.random()
}

/**
 * Génère un ID unique pour les requêtes WS.
 */
export function generateRequestId(prefix = 'req') {
  return `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`
}

