/**
 * MyBotIA WebSocket Protocol — OpenClaw Gateway v3
 * 
 * Validated E2E:
 * - connect as openclaw-control-ui → operator.write scope ✅
 * - sessions.messages.subscribe {key} → receives session.message events ✅  
 * - sessions.send {key, message, idempotencyKey} → ok=true ✅
 * - session.message event → role=assistant, content=[{type:"text", text:"..."}] ✅
 */

const PROTOCOL_VERSION = 3

/**
 * Reconnect delay with exponential backoff + jitter.
 */
export function reconnectDelayMs(attempt) {
  const baseMs = 1000
  const maxMs = 30000
  const jitterMs = 1000
  const backoff = Math.min(baseMs * 2 ** Math.max(0, attempt), maxMs)
  return backoff + jitterMs * Math.random()
}

/**
 * Generate unique request ID.
 */
export function generateRequestId(prefix = 'req') {
  return `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`
}

/**
 * Generate UUID v4.
 */
export function uuid() {
  return crypto.randomUUID?.() ||
    'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
      const r = Math.random() * 16 | 0
      return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16)
    })
}

/**
 * Build connect payload.
 * client.id = 'openclaw-control-ui' → gives operator.write scope (required for sessions.send)
 * NOTE: This mode does NOT return sessionDefaults. We get sessions via sessions.list.
 */
export function buildConnectPayload(nonce, token) {
  return {
    type: 'req',
    id: generateRequestId('connect'),
    method: 'connect',
    params: {
      minProtocol: PROTOCOL_VERSION,
      maxProtocol: PROTOCOL_VERSION,
      client: {
        id: 'openclaw-control-ui',
        version: '1.0.0',
        platform: 'chrome-extension',
        mode: 'ui',
        displayName: 'MyBotIA Browser',
        deviceFamily: 'browser',
      },
      role: 'operator',
      scopes: ['operator.read', 'operator.write'],
      auth: token ? { token } : undefined,
    },
  }
}

/**
 * Build sessions.send payload.
 * IMPORTANT: uses 'key' (not 'sessionKey') and 'message' (not 'text')
 */
export function buildSessionsSendPayload(sessionKey, text) {
  return {
    type: 'req',
    id: generateRequestId('send'),
    method: 'sessions.send',
    params: {
      key: sessionKey,
      message: text,
      idempotencyKey: uuid(),
    },
  }
}

/**
 * Build sessions.messages.subscribe payload.
 * After subscribing, we receive session.message events for this session.
 */
export function buildSubscribePayload(sessionKey) {
  return {
    type: 'req',
    id: generateRequestId('sub'),
    method: 'sessions.messages.subscribe',
    params: {
      key: sessionKey,
    },
  }
}

/**
 * Build sessions.list payload to discover available sessions.
 */
export function buildSessionsListPayload() {
  return {
    type: 'req',
    id: generateRequestId('sessions'),
    method: 'sessions.list',
    params: {},
  }
}

/**
 * Extract text from an OpenClaw message content.
 * Content can be a string or an array of {type: "text", text: "..."} blocks.
 */
export function extractMessageText(content) {
  if (!content) return ''
  if (typeof content === 'string') return content
  if (Array.isArray(content)) {
    return content
      .filter(block => block?.type === 'text' && block?.text)
      .map(block => block.text)
      .join('\n')
  }
  return String(content)
}

/**
 * MyBotIA Browser Extension — Background Service Worker
 * 
 * Protocol flow:
 * 1. connect as openclaw-control-ui (operator scope)
 * 2. sessions.list → find default session (agent:main:main)
 * 3. sessions.messages.subscribe → receive session.message events
 * 4. sessions.send → send user messages
 * 5. session.message events → forward assistant responses to sidepanel
 */

import {
  reconnectDelayMs,
  generateRequestId,
  buildConnectPayload,
  buildSessionsSendPayload,
  buildSubscribePayload,
  buildSessionsListPayload,
  extractMessageText,
} from './lib/ws-protocol.js'

// --- State ---
let ws = null
let wsConnectPromise = null
let gatewayConnected = false
let connectRequestId = null
let reconnectAttempt = 0
let reconnectTimer = null
let currentSessionKey = '' // Discovered via sessions.list or config

const pendingRequests = new Map()

// --- Storage helpers ---
async function getConfig() {
  const stored = await chrome.storage.local.get([
    'gatewayUrl',
    'gatewayToken',
    'agentId',
    'sessionKey',
  ])
  return {
    gatewayUrl: stored.gatewayUrl || 'wss://app.mybotia.com/ws',
    gatewayToken: stored.gatewayToken || '',
    agentId: stored.agentId || '',
    sessionKey: stored.sessionKey || '', // Optional override
  }
}

// --- Badge ---
const BADGE = {
  connected: { text: '●', color: '#16a34a' },
  connecting: { text: '…', color: '#F59E0B' },
  error: { text: '!', color: '#B91C1C' },
  off: { text: '', color: '#000000' },
}

function setBadge(kind) {
  const cfg = BADGE[kind] || BADGE.off
  chrome.action.setBadgeText({ text: cfg.text }).catch(() => {})
  chrome.action.setBadgeBackgroundColor({ color: cfg.color }).catch(() => {})
  chrome.action.setBadgeTextColor({ color: '#FFFFFF' }).catch(() => {})
}

// --- WebSocket connection ---
async function connect() {
  if (ws && ws.readyState === WebSocket.OPEN) return
  if (wsConnectPromise) return await wsConnectPromise

  wsConnectPromise = _doConnect()
  try {
    await wsConnectPromise
    reconnectAttempt = 0
  } finally {
    wsConnectPromise = null
  }
}

async function _doConnect() {
  const config = await getConfig()
  if (!config.gatewayToken) {
    setBadge('error')
    throw new Error('Token gateway manquant — configurer dans les options')
  }

  setBadge('connecting')
  broadcastToUI({ type: 'connection-status', status: 'connecting' })

  const wsUrl = config.gatewayUrl.replace(/\/$/, '')
  const socket = new WebSocket(wsUrl)
  ws = socket

  socket.onmessage = (event) => {
    if (socket !== ws) return
    onMessage(String(event.data || ''))
  }

  await new Promise((resolve, reject) => {
    const timeout = setTimeout(() => reject(new Error('WebSocket connect timeout')), 8000)
    socket.onopen = () => { clearTimeout(timeout); resolve() }
    socket.onerror = () => { clearTimeout(timeout); reject(new Error('WebSocket connect failed')) }
    socket.onclose = (ev) => { clearTimeout(timeout); reject(new Error(`WebSocket closed (${ev.code})`)) }
  })

  socket.onclose = () => { if (socket === ws) onDisconnected('closed') }
  socket.onerror = () => { if (socket === ws) onDisconnected('error') }
}

function onDisconnected(reason) {
  ws = null
  gatewayConnected = false
  connectRequestId = null

  for (const [id, p] of pendingRequests.entries()) {
    pendingRequests.delete(id)
    p.reject(new Error(`Déconnecté (${reason})`))
  }

  setBadge('error')
  broadcastToUI({ type: 'connection-status', status: 'disconnected', reason })
  scheduleReconnect()
}

function scheduleReconnect() {
  if (reconnectTimer) clearTimeout(reconnectTimer)
  const delay = reconnectDelayMs(reconnectAttempt)
  reconnectAttempt++
  reconnectTimer = setTimeout(async () => {
    reconnectTimer = null
    try { await connect() } catch { scheduleReconnect() }
  }, delay)
}

function cancelReconnect() {
  if (reconnectTimer) { clearTimeout(reconnectTimer); reconnectTimer = null }
  reconnectAttempt = 0
}

// --- Message handling ---
function send(payload) {
  if (!ws || ws.readyState !== WebSocket.OPEN) throw new Error('WebSocket non connecté')
  ws.send(JSON.stringify(payload))
}

function sendRequest(payload) {
  return new Promise((resolve, reject) => {
    const id = payload.id
    const timer = setTimeout(() => {
      pendingRequests.delete(id)
      reject(new Error('Timeout requête (30s)'))
    }, 30000)

    pendingRequests.set(id, {
      resolve: (v) => { clearTimeout(timer); resolve(v) },
      reject: (e) => { clearTimeout(timer); reject(e) },
    })

    try { send(payload) } catch (err) {
      clearTimeout(timer)
      pendingRequests.delete(id)
      reject(err)
    }
  })
}

async function onMessage(text) {
  let msg
  try { msg = JSON.parse(text) } catch { return }

  // Gateway connect challenge
  if (msg?.type === 'event' && msg?.event === 'connect.challenge') {
    try {
      const config = await getConfig()
      const payload = buildConnectPayload(msg.payload?.nonce, config.gatewayToken)
      connectRequestId = payload.id
      send(payload)
    } catch (err) {
      console.warn('Handshake failed:', err)
      connectRequestId = null
      ws?.close(1008, 'handshake failed')
    }
    return
  }

  // Connect response
  if (msg?.type === 'res' && connectRequestId && msg?.id === connectRequestId) {
    connectRequestId = null
    if (msg.ok) {
      gatewayConnected = true
      setBadge('connected')

      // After connect: discover session and subscribe
      await setupSession()

      broadcastToUI({
        type: 'connection-status',
        status: 'connected',
        sessionKey: currentSessionKey,
        features: msg.payload?.features,
      })
    } else {
      console.warn('Gateway connect rejected:', msg.error)
      setBadge('error')
      broadcastToUI({
        type: 'connection-status',
        status: 'error',
        error: msg.error?.message || 'Connexion refusée',
      })
      ws?.close(1008, 'connect rejected')
    }
    return
  }

  // Ping/pong
  if (msg?.method === 'ping') {
    try { send({ method: 'pong' }) } catch {}
    return
  }

  // Response to a pending request
  if (msg?.type === 'res' && msg?.id) {
    const p = pendingRequests.get(msg.id)
    if (p) {
      pendingRequests.delete(msg.id)
      if (msg.ok) p.resolve(msg.payload)
      else p.reject(new Error(msg.error?.message || 'Erreur gateway'))
    }
    return
  }

  // Events → forward to UI
  if (msg?.type === 'event') {
    const event = msg.event
    const payload = msg.payload || {}

    // session.message → extract and forward assistant messages
    if (event === 'session.message' && payload.sessionKey === currentSessionKey) {
      const message = payload.message
      if (message?.role === 'assistant') {
        const text = extractMessageText(message.content)
        if (text && text !== 'NO_REPLY' && text !== 'HEARTBEAT_OK') {
          broadcastToUI({
            type: 'assistant-message',
            text,
            timestamp: message.timestamp || Date.now(),
            messageId: payload.messageId || message?.__openclaw?.id,
          })
        }
      }
    }

    // Also forward raw events for debugging/future use
    broadcastToUI({
      type: 'gateway-event',
      event,
      payload,
      seq: msg.seq,
    })
    return
  }
}

// --- Session setup (after connect) ---
async function setupSession() {
  const config = await getConfig()

  // Use configured sessionKey or default to agent:main:main
  if (config.sessionKey) {
    currentSessionKey = config.sessionKey
  } else {
    // Try to find the main session via sessions.list
    try {
      const result = await sendRequest(buildSessionsListPayload())
      const sessions = result?.sessions || []
      // Look for agent:main:main or the first webchat direct session
      const mainSession = sessions.find(s => s.key === 'agent:main:main')
        || sessions.find(s => s.kind === 'direct' && s.origin?.provider === 'webchat')
        || sessions[0]
      currentSessionKey = mainSession?.key || 'agent:main:main'
    } catch (err) {
      console.warn('sessions.list failed, using default:', err)
      currentSessionKey = 'agent:main:main'
    }
  }

  // Subscribe to session messages
  try {
    await sendRequest(buildSubscribePayload(currentSessionKey))
    console.log('Subscribed to session:', currentSessionKey)
  } catch (err) {
    console.warn('Subscribe failed:', err)
  }
}

// --- Communication with UI ---
function broadcastToUI(message) {
  chrome.runtime.sendMessage(message).catch(() => {})
}

// --- Handle messages from sidepanel/popup/options ---
chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
  if (!msg?.action) return false

  switch (msg.action) {
    case 'get-status':
      sendResponse({
        connected: gatewayConnected,
        sessionKey: currentSessionKey,
      })
      return false

    case 'connect':
      cancelReconnect()
      connect()
        .then(() => sendResponse({ ok: true }))
        .catch(err => sendResponse({ ok: false, error: err.message }))
      return true

    case 'disconnect':
      cancelReconnect()
      if (ws) ws.close(1000, 'user disconnect')
      ws = null
      gatewayConnected = false
      currentSessionKey = ''
      setBadge('off')
      sendResponse({ ok: true })
      return false

    case 'chat-send': {
      const sk = msg.sessionKey || currentSessionKey
      if (!sk) {
        sendResponse({ ok: false, error: 'Pas de session active' })
        return false
      }
      const payload = buildSessionsSendPayload(sk, msg.text)
      sendRequest(payload)
        .then(result => sendResponse({ ok: true, result }))
        .catch(err => sendResponse({ ok: false, error: err.message }))
      return true
    }

    case 'get-page-context':
      chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
        if (!tabs[0]?.id) {
          sendResponse({ ok: false, error: 'Pas d\'onglet actif' })
          return
        }
        chrome.tabs.sendMessage(tabs[0].id, { action: 'extract-context' }, (response) => {
          if (chrome.runtime.lastError) {
            sendResponse({ ok: false, error: chrome.runtime.lastError.message })
          } else {
            sendResponse({ ok: true, context: response })
          }
        })
      })
      return true

    default:
      return false
  }
})

// --- Side Panel behavior ---
chrome.sidePanel.setPanelBehavior({ openPanelOnActionClick: true }).catch(() => {})

// Context menu
chrome.contextMenus?.onClicked.addListener((info) => {
  if (info.menuItemId === 'mybotia-options') {
    chrome.runtime.openOptionsPage()
  } else if (info.menuItemId === 'mybotia-disconnect') {
    cancelReconnect()
    if (ws) ws.close(1000, 'user disconnect')
    ws = null
    gatewayConnected = false
    currentSessionKey = ''
    setBadge('off')
    broadcastToUI({ type: 'connection-status', status: 'disconnected' })
  }
})

// --- Keepalive ---
chrome.alarms.create('mybotia-keepalive', { periodInMinutes: 0.5 })
chrome.alarms.onAlarm.addListener(async (alarm) => {
  if (alarm.name !== 'mybotia-keepalive') return
  if (!ws || ws.readyState !== WebSocket.OPEN) {
    if (!wsConnectPromise && !reconnectTimer) {
      connect().catch(() => { if (!reconnectTimer) scheduleReconnect() })
    }
  }
})

// --- Init on install ---
chrome.runtime.onInstalled.addListener(async () => {
  chrome.contextMenus?.create({ id: 'mybotia-options', title: 'MyBotIA — Options', contexts: ['action'] })
  chrome.contextMenus?.create({ id: 'mybotia-disconnect', title: 'Déconnecter', contexts: ['action'] })

  const config = await getConfig()
  if (config.gatewayToken) {
    connect().catch(() => {})
  } else {
    chrome.runtime.openOptionsPage()
  }
})

// --- Auto-connect on startup ---
getConfig().then(config => {
  if (config.gatewayToken) {
    connect().catch(() => scheduleReconnect())
  }
})

/**
 * MyBotIA Side Panel — Chat UI Logic
 * 
 * Receives messages via:
 * - 'assistant-message' type from background (extracted from session.message events)
 * - 'connection-status' type from background
 */

// --- DOM refs ---
const messagesEl = document.getElementById('messages')
const messagesEmpty = document.getElementById('messages-empty')
const inputEl = document.getElementById('input')
const btnSend = document.getElementById('btn-send')
const btnContext = document.getElementById('btn-context')
const btnSettings = document.getElementById('btn-settings')
const statusDot = document.getElementById('status-dot')
const statusText = document.getElementById('status-text')
const agentName = document.getElementById('agent-name')
const typingIndicator = document.getElementById('typing-indicator')
const pageContext = document.getElementById('page-context')
const pageContextUrl = document.getElementById('page-context-url')
const pageContextClose = document.getElementById('page-context-close')
const connectionOverlay = document.getElementById('connection-overlay')
const btnOverlayConnect = document.getElementById('btn-overlay-connect')
const overlayMessage = document.getElementById('overlay-message')

// --- State ---
let messages = []
let includePageContext = false
let isConnected = false
let currentSessionKey = ''
let typingTimeout = null
const displayedMessageIds = new Set() // Prevent duplicate messages

// --- Init ---
async function init() {
  chrome.runtime.sendMessage({ action: 'get-status' }, (response) => {
    if (chrome.runtime.lastError) {
      updateConnectionUI('disconnected')
      return
    }
    if (response?.connected) {
      updateConnectionUI('connected')
      currentSessionKey = response.sessionKey || ''
      agentName.textContent = 'Léa' // Default agent name
    } else {
      updateConnectionUI('disconnected')
    }
  })
}

// --- Connection UI ---
function updateConnectionUI(status, error) {
  statusDot.className = 'status-dot'

  switch (status) {
    case 'connected':
      statusDot.classList.add('connected')
      statusText.textContent = 'En ligne'
      connectionOverlay.classList.remove('visible')
      isConnected = true
      btnSend.disabled = !inputEl.value.trim()
      break

    case 'connecting':
      statusDot.classList.add('connecting')
      statusText.textContent = 'Connexion...'
      isConnected = false
      btnSend.disabled = true
      break

    case 'disconnected':
      statusText.textContent = 'Déconnecté'
      isConnected = false
      btnSend.disabled = true
      connectionOverlay.classList.add('visible')
      overlayMessage.textContent = error || 'Configurez votre token pour vous connecter.'
      break

    case 'error':
      statusDot.classList.add('error')
      statusText.textContent = 'Erreur'
      isConnected = false
      btnSend.disabled = true
      connectionOverlay.classList.add('visible')
      overlayMessage.textContent = error || 'Erreur de connexion.'
      break
  }
}

// --- Messages ---
function addMessage(role, text, timestamp, messageId) {
  // Deduplicate
  if (messageId && displayedMessageIds.has(messageId)) return
  if (messageId) displayedMessageIds.add(messageId)

  messages.push({ role, text, timestamp: timestamp || Date.now() })
  messagesEmpty.style.display = 'none'
  renderMessage(role, text, timestamp)
  scrollToBottom()
}

function renderMessage(role, text, timestamp) {
  const div = document.createElement('div')
  div.className = `message ${role}`

  const avatar = document.createElement('div')
  avatar.className = 'message-avatar'
  avatar.textContent = role === 'user' ? 'V' : '📋'

  const bubble = document.createElement('div')
  bubble.className = 'message-bubble'
  bubble.innerHTML = renderMarkdown(text)

  const time = document.createElement('div')
  time.className = 'message-time'
  time.textContent = formatTime(timestamp || Date.now())

  const content = document.createElement('div')
  content.appendChild(bubble)
  content.appendChild(time)

  div.appendChild(avatar)
  div.appendChild(content)
  messagesEl.appendChild(div)
}

function renderMarkdown(text) {
  if (!text) return ''
  return text
    .replace(/```(\w*)\n?([\s\S]*?)```/g, '<pre><code>$2</code></pre>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>')
    .replace(/^[*-] (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>')
    .replace(/\n/g, '<br>')
}

function formatTime(ts) {
  const d = new Date(ts)
  return d.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })
}

function scrollToBottom() {
  requestAnimationFrame(() => {
    messagesEl.scrollTop = messagesEl.scrollHeight
  })
}

function showTyping() {
  typingIndicator.classList.add('visible')
  scrollToBottom()
}

function hideTyping() {
  typingIndicator.classList.remove('visible')
}

// --- Send message ---
async function sendMessage() {
  const text = inputEl.value.trim()
  if (!text || !isConnected) return

  inputEl.value = ''
  inputEl.style.height = 'auto'
  btnSend.disabled = true

  // Add user message immediately
  addMessage('user', text)

  // Build metadata with page context if enabled
  let metadata = {}
  if (includePageContext) {
    try {
      const ctx = await getPageContext()
      if (ctx) metadata.pageContext = ctx
    } catch {}
  }

  showTyping()

  chrome.runtime.sendMessage(
    {
      action: 'chat-send',
      sessionKey: currentSessionKey,
      text: includePageContext && metadata.pageContext
        ? `${text}\n\n[Contexte page: ${metadata.pageContext.url}]\n${metadata.pageContext.title || ''}`
        : text,
    },
    (response) => {
      if (chrome.runtime.lastError) {
        hideTyping()
        addMessage('assistant', '❌ Erreur : impossible d\'envoyer le message.')
        return
      }
      if (!response?.ok) {
        hideTyping()
        addMessage('assistant', `❌ Erreur : ${response?.error || 'inconnue'}`)
      }
      // Response will come via session.message event → assistant-message broadcast
    }
  )
}

// --- Page context ---
function getPageContext() {
  return new Promise((resolve) => {
    chrome.runtime.sendMessage({ action: 'get-page-context' }, (response) => {
      if (chrome.runtime.lastError || !response?.ok) {
        resolve(null)
        return
      }
      resolve(response.context)
    })
  })
}

function togglePageContext() {
  includePageContext = !includePageContext
  btnContext.classList.toggle('active', includePageContext)

  if (includePageContext) {
    getPageContext().then(ctx => {
      if (ctx) {
        pageContext.classList.add('visible')
        pageContextUrl.textContent = ctx.url || 'Page active'
      }
    })
  } else {
    pageContext.classList.remove('visible')
  }
}

// --- Event listeners ---
inputEl.addEventListener('input', () => {
  inputEl.style.height = 'auto'
  inputEl.style.height = Math.min(inputEl.scrollHeight, 120) + 'px'
  btnSend.disabled = !inputEl.value.trim() || !isConnected
})

inputEl.addEventListener('keydown', (e) => {
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault()
    sendMessage()
  }
})

btnSend.addEventListener('click', sendMessage)
btnContext.addEventListener('click', togglePageContext)
pageContextClose.addEventListener('click', () => {
  includePageContext = false
  btnContext.classList.remove('active')
  pageContext.classList.remove('visible')
})

btnSettings.addEventListener('click', () => chrome.runtime.openOptionsPage())
btnOverlayConnect.addEventListener('click', () => chrome.runtime.openOptionsPage())

// --- Listen for events from background ---
chrome.runtime.onMessage.addListener((msg) => {
  if (!msg?.type) return

  switch (msg.type) {
    case 'connection-status':
      updateConnectionUI(msg.status, msg.error)
      if (msg.status === 'connected') {
        currentSessionKey = msg.sessionKey || currentSessionKey
        agentName.textContent = 'Léa'
      }
      break

    case 'assistant-message':
      // Direct assistant message from background (extracted from session.message event)
      hideTyping()
      addMessage('assistant', msg.text, msg.timestamp, msg.messageId)
      break

    case 'gateway-event':
      // Handle other events (typing, etc.)
      if (msg.event === 'agent') {
        const data = msg.payload?.data
        if (data?.state === 'delta' || data?.stream) {
          showTyping()
          if (typingTimeout) clearTimeout(typingTimeout)
          typingTimeout = setTimeout(hideTyping, 15000)
        }
      }
      break
  }
})

// --- Start ---
init()

arguments.newText:
