/**
 * Extrait le texte visible en ignorant les éléments cachés et les scripts.
 */
function extractVisibleText(element) {
  const IGNORED_TAGS = new Set([
    'SCRIPT', 'STYLE', 'NOSCRIPT', 'SVG', 'IFRAME', 'OBJECT', 'EMBED',
    'HEAD', 'META', 'LINK',
  ])

  let text = ''

  function walk(node) {
    if (node.nodeType === Node.TEXT_NODE) {
      const t = node.textContent?.trim()
      if (t) text += t + ' '
      return
    }

    if (node.nodeType !== Node.ELEMENT_NODE) return
    if (IGNORED_TAGS.has(node.tagName)) return

    // Check visibility
    const style = window.getComputedStyle(node)
    if (style.display === 'none' || style.visibility === 'hidden') return

    for (const child of node.childNodes) {
      walk(child)
    }

    // Add line break after block elements
    const display = style.display
    if (display === 'block' || display === 'flex' || display === 'grid' ||
        node.tagName === 'BR' || node.tagName === 'P' || node.tagName === 'DIV') {
      text += '\n'
    }
  }

  walk(element)
  return text.replace(/\n{3,}/g, '\n\n').trim()
}

/**
 * Trouve le label associé à un input.
 */
function findLabel(input) {
  // Label via for attribute
  if (input.id) {
    const label = document.querySelector(`label[for="${CSS.escape(input.id)}"]`)
    if (label) return label.textContent?.trim().slice(0, 100) || ''
  }

  // Label parent
