/**
 * Highlight visuel temporaire d'un élément.
 */
function highlightElement(el) {
  const overlay = document.createElement('div')
  overlay.style.cssText = `
    position: absolute;
    pointer-events: none;
    border: 2px solid #3b82f6;
    background: rgba(59, 130, 246, 0.1);
    border-radius: 4px;
    z-index: 999999;
    transition: opacity 0.3s;
  `

  const rect = el.getBoundingClientRect()
  overlay.style.left = (rect.left + window.scrollX - 2) + 'px'
  overlay.style.top = (rect.top + window.scrollY - 2) + 'px'
  overlay.style.width = (rect.width + 4) + 'px'
  overlay.style.height = (rect.height + 4) + 'px'

  document.body.appendChild(overlay)
  setTimeout(() => {
    overlay.style.opacity = '0'
    setTimeout(() => overlay.remove(), 300)
  }, 1500)
}

// --- Agent glow overlay (Phase 3 — feedback visuel prise en main) ---

let glowOverlay = null

function showAgentGlow() {
  if (glowOverlay) return
  glowOverlay = document.createElement('div')
  glowOverlay.id = 'mybotia-agent-glow'

  const style = document.createElement('style')
  style.id = 'mybotia-agent-glow-style'
  style.textContent = `
    @keyframes mybotia-glow-pulse {
      0%, 100% { opacity: 0.6; }
      50% { opacity: 1; }
    }
    #mybotia-agent-glow {
      position: fixed;
      inset: 0;
      pointer-events: none;
      z-index: 2147483647;
      border: 3px solid rgba(37, 99, 235, 0.6);
      box-shadow: inset 0 0 40px rgba(37, 99, 235, 0.15),
                  0 0 40px rgba(37, 99, 235, 0.1);
      border-radius: 0;
      animation: mybotia-glow-pulse 2s ease-in-out infinite;
      transition: opacity 0.3s ease;
    }
  `
  document.documentElement.appendChild(style)
  document.documentElement.appendChild(glowOverlay)
}

function hideAgentGlow() {
  if (!glowOverlay) return
  glowOverlay.style.opacity = '0'
  const overlay = glowOverlay
  const style = document.getElementById('mybotia-agent-glow-style')
  setTimeout(() => {
    overlay.remove()
    style?.remove()
  }, 300)
  glowOverlay = null
}

// --- Message handler ---
chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
  if (!msg?.action) return false

  switch (msg.action) {
    case 'extract-context':
      try {
        const context = extractPageContext()
        sendResponse(context)
      } catch (err) {
        sendResponse({ error: err.message })
      }
      return false

    case 'fill-field':
      showAgentGlow()
      sendResponse(fillField(msg.selector, msg.value))
      return false

    case 'click-element':
      showAgentGlow()
      sendResponse(clickElement(msg.selector))
      return false

    case 'navigate':
      showAgentGlow()
      window.location.href = msg.url
      sendResponse({ ok: true })
      return false

    case 'agent-glow-start':
      showAgentGlow()
      sendResponse({ ok: true })
      return false

    case 'agent-glow-stop':
      hideAgentGlow()
      sendResponse({ ok: true })
      return false

    case 'screenshot':
      sendResponse({ ok: false, error: 'Screenshot via background.js' })
      return false

    default:
      return false
  }
})

